                totalLoss += loss;

                // Free tensors
                anchorLocal_.FreeTensor(anchorVec);
                posLocal_.FreeTensor(posVec);
                negLocal_.FreeTensor(negVec);
            }
            processed += cur;
        }

        float meanLoss = totalLoss / static_cast<float>(totalSamples_);
        yGm_.SetValue(0, meanLoss);
    }

